PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "items" ("id" integer primary key autoincrement not null, "title" varchar not null, "colour" varchar, "icon" varchar, "url" varchar not null, "description" text, "pinned" tinyint(1) not null default '0', "order" integer not null default '0', "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, "type" integer not null default '0', "user_id" integer not null default '1', "class" varchar, "appid" varchar, "appdescription" text);
CREATE TABLE IF NOT EXISTS "settings" ("id" integer primary key autoincrement not null, "group_id" integer not null default '0', "key" varchar not null, "type" varchar not null default 'text', "options" text, "label" varchar not null, "value" varchar, "order" varchar not null default '0', "system" tinyint(1) not null default '0');
CREATE TABLE IF NOT EXISTS "setting_groups" ("id" integer primary key autoincrement not null, "title" varchar not null, "order" integer not null default '0');
CREATE TABLE IF NOT EXISTS "item_tag" ("item_id" integer not null, "tag_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("item_id") references "items"("id") on delete cascade, foreign key("tag_id") references "items"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "username" varchar not null, "email" varchar not null, "avatar" varchar, "password" varchar, "autologin" varchar, "public_front" tinyint(1) not null default '0', "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime);
CREATE TABLE IF NOT EXISTS "setting_user" ("setting_id" integer not null, "user_id" integer not null, "uservalue" varchar, foreign key("setting_id") references "settings"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade, primary key ("setting_id", "user_id"));
CREATE TABLE IF NOT EXISTS "applications" ("appid" varchar not null, "name" varchar not null, "sha" varchar, "icon" varchar, "website" varchar, "license" varchar, "description" text, "enhanced" tinyint(1) not null default '0', "tile_background" varchar not null default 'dark', "created_at" datetime, "updated_at" datetime, "class" varchar);
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE INDEX "items_type_index" on "items" ("type");
CREATE INDEX "item_tag_item_id_index" on "item_tag" ("item_id");
CREATE INDEX "item_tag_tag_id_index" on "item_tag" ("tag_id");
CREATE UNIQUE INDEX "users_username_unique" on "users" ("username");
CREATE INDEX "users_autologin_index" on "users" ("autologin");
CREATE INDEX "password_resets_email_index" on "password_reset_tokens" ("email");
CREATE INDEX "items_user_id_index" on "items" ("user_id");
CREATE INDEX "setting_user_setting_id_index" on "setting_user" ("setting_id");
CREATE INDEX "setting_user_user_id_index" on "setting_user" ("user_id");
CREATE UNIQUE INDEX "applications_appid_unique" on "applications" ("appid");
CREATE UNIQUE INDEX "applications_name_unique" on "applications" ("name");
CREATE UNIQUE INDEX "applications_sha_unique" on "applications" ("sha");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE INDEX "applications_class_index" on "applications" ("class");
COMMIT;
