INSERT INTO items VALUES(1,'Jellyfin','#161b1f','icons/jellyfin.svg','jellyfin.lan','{"enabled":"0","override_url":null,"password":null}',1,0,NULL,'2025-05-26 03:12:50','2025-05-26 03:23:44',0,1,'App\SupportedApps\Jellyfin\Jellyfin','3e0a7f109bd760b9474c78cb652e8c3e82669226','Jellyfin is the Free Software Media System that puts you in control of managing and streaming your media. There are no strings attached, no premium licenses or features, and no hidden agendas.');
INSERT INTO items VALUES(2,'qBittorrent','#161b1f','icons/qbittorrent.svg','http://qbittorrent.replace_domain/','{"enabled":"0","override_url":null,"username":null,"password":null}',1,0,NULL,'2025-05-26 04:16:10','2025-05-26 04:16:10',0,1,'App\SupportedApps\qBittorrent\qBittorrent','3ebd4dd8afe6308e392ccf09e3516eee99a1e8df','The qBittorrent project aims to provide an open-source software alternative to µTorrent.');
INSERT INTO items VALUES(3,'Traefik','#161b1f','icons/traefik.svg','http://traefik.replace_domain/','{"enabled":"0","override_url":null,"fields":"E","ignore_tls":"0","username":null,"password":null}',1,0,NULL,'2025-05-26 04:17:34','2025-05-26 04:17:34',0,1,'App\SupportedApps\Traefik\Traefik','a83e2ce54bbef3bef63aa7f02b08dbda7fdae4c5','Træfik is a modern HTTP reverse proxy and load balancer that makes deploying microservices easy. Træfik integrates with your existing infrastructure components and configures itself automatically and dynamically.');
INSERT INTO items VALUES(4,'Radarr','#000','icons/radarr.svg','http://radarr.replace_domain/','{"enabled":"0","override_url":null,"apikey":null}',1,0,NULL,'2025-05-26 04:18:10','2025-05-26 04:20:10',0,1,'App\SupportedApps\Radarr\Radarr','8a5cd39a1a5dff323d63bbe45fffe0c9c03bd2e7',replace(replace('Radarr is an independent fork of Sonarr reworked for automatically downloading movies via Usenet and BitTorrent.\r\n\r\nThe project was inspired by other Usenet/BitTorrent movie downloaders such as CouchPotato.','\r',char(13)),'\n',char(10)));
INSERT INTO items VALUES(5,'Heimdall','#161b1f','icons/heimdall.png','http://heimdall.replace_domain/','{"enabled":"0","override_url":null}',1,0,'2025-05-26 04:21:41','2025-05-26 04:19:02','2025-05-26 04:21:41',0,1,'App\SupportedApps\Heimdall\Heimdall','b2005b3bb19b3916425998c0edd72b97667ec1fc',replace(replace('As the name suggests Heimdall Application Dashboard is a dashboard for all your web applications. It doesn''t need to be limited to applications though, you can add links to anything you like.\r\nHeimdall is an elegant solution to organise all your web applications. It’s dedicated to this purpose so you won’t lose your links in a sea of bookmarks.\r\nWhy not use it as your browser start page? It even has the ability to include a search bar using either Google, Bing or DuckDuckGo.','\r',char(13)),'\n',char(10)));
INSERT INTO items VALUES(6,'Prowlarr','#161b1f','icons/prowlarr.svg','http://prowlarr.replace_domain/','{"enabled":"0","override_url":null,"apikey":null}',1,0,NULL,'2025-05-26 04:19:47','2025-05-26 04:19:47',0,1,'App\SupportedApps\Prowlarr\Prowlarr','de6ff49c94538e6e13a77f75991141a4fe9af8bf','Prowlarr is a indexer manager/proxy built on the popular arr .net/reactjs base stack to integrate with your various PVR apps. Prowlarr supports both Torrent Trackers and Usenet Indexers. It integrates seamlessly with Sonarr, Radarr, Lidarr, and Readarr offering complete management of your indexers with no per app Indexer setup required (we do it all).');
